/// <summary>
/// While opening the form, if the CapexId feature flag is enabled
/// then only the field Capexapprovalid is visible
/// </summary>
void init()
{
    next init();
    FormRun formRun = this as FormRun;
    formRun.design().controlName(FormControlstr(LedgerTransVoucher, GeneralJournalAccountEntry_ETGCapexApprovalId)).visible(AssetParameters::find().ETGCapexApprovalIdFeature);
}
